function MyRegistrationsPage() {
  const registrations = [
    {
      id: 1,
      title: "Cloud Security Workshop",
      date: "2026-04-10",
      location: "Dublin",
    },
    {
      id: 2,
      title: "DevOps Bootcamp",
      date: "2026-04-15",
      location: "Online",
    },
  ];

  return (
    <div className="page-box">
      <h2>My Registrations</h2>
      <p>These are the events you have registered for.</p>

      {registrations.map((event) => (
        <div
          key={event.id}
          style={{
            border: "1px solid #ddd",
            borderRadius: "8px",
            padding: "15px",
            marginBottom: "15px",
            backgroundColor: "#fafafa",
          }}
        >
          <h3>{event.title}</h3>
          <p><strong>Date:</strong> {event.date}</p>
          <p><strong>Location:</strong> {event.location}</p>

          <button
            style={{
              padding: "8px 16px",
              backgroundColor: "#b91c1c",
              color: "white",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer",
            }}
            onClick={() => alert(`Registration cancelled for ${event.title}`)}
          >
            Cancel Registration
          </button>
        </div>
      ))}
    </div>
  );
}

export default MyRegistrationsPage;
